A stack is to be implemented using an array. The associated declarations are: 
int stack [100]; 
int top = -1; 
Give the statement to perform PUSH and POP operation.

blocks.content:
#include <stdio.h>

#define MAX 100
int stack[MAX];
int top = -1;

// Function to push an element
void push(int value) {
    if (top == MAX - 1) {
        printf("Stack Overflow: Cannot push %d
", value);
    } else {
        top++;
        stack[top] = value;
        printf("Pushed %d onto stack
", value);
    }
}

// Function to pop an element
void pop() {
    if (top == -1) {
        printf("Stack Underflow: Cannot pop from empty stack
");
    } else {
        printf("Popped %d from stack
", stack[top]);
        top--;
    }
}

int main() {
    push(10);
    push(20);
    pop();
    pop();
    pop(); // Triggers underflow
    return 0;
}
